 10→/* ═══ LIGHT MODE (default) — Frase.io inspired ═══ */
 11→:root {
 12→  /* Surfaces */
 13→  --bg-base:        #FAFAF8;
 14→  --bg-surface:     #FFFFFF;
 15→  --bg-elevated:    #F5F5F3;
 16→  --bg-overlay:     #E5E7EB;
 17→  --bg-sidebar:     #FFFFFF;
 18→
 19→  /* Borders */
 20→  --border-default: #E5E7EB;
 21→  --border-subtle:  #F0F0EE;
 22→  --border-strong:  #D1D5DB;
 23→
 24→  /* Text */
 25→  --text-primary:   #1A1A1A;
 26→  --text-secondary: #6B7280;
 27→  --text-tertiary:  #9CA3AF;
 28→  --text-disabled:  #D1D5DB;
 29→
 30→  /* Accents — Forest green (Frase.io) */
 31→  --accent:         #059669;
 32→  --accent-hover:   #047857;
 33→  --accent-subtle:  rgba(5, 150, 105, 0.08);
 34→  --accent-text:    #059669;
 35→
 36→  /* Semantic */
 37→  --success:        #16A34A;
 38→  --success-subtle: rgba(22, 163, 74, 0.08);
 39→  --warning:        #D97706;
 40→  --warning-subtle: rgba(217, 119, 6, 0.08);
 41→  --error:          #DC2626;
 42→  --error-subtle:   rgba(220, 38, 38, 0.08);
 43→
 44→  /* AI Engine identity */
 45→  --engine-chatgpt:    #10B981;
 46→  --engine-perplexity: #3B82F6;
 47→  --engine-gemini:     #8B5CF6;
 48→
 49→  /* Glassmorphism */
 50→  --glass-bg:            rgba(255, 255, 255, 0.8);
 51→  --glass-bg-strong:     rgba(255, 255, 255, 0.9);
 52→  --glass-border:        rgba(0, 0, 0, 0.06);
 53→  --glass-border-hover:  rgba(0, 0, 0, 0.1);
 54→  --glass-surface:       rgba(0, 0, 0, 0.02);
 55→  --glass-surface-hover: rgba(0, 0, 0, 0.04);
 56→  --glass-active:        rgba(0, 0, 0, 0.06);
 57→
 58→  color-scheme: light;
 59→}
 60→
