 67→  --bg-sidebar:     #0F0F11;
 68→
 69→  --border-default: #27272A;
 70→  --border-subtle:  #1E1E22;
 71→  --border-strong:  #3F3F46;
 72→
 73→  --text-primary:   #FAFAFA;
 74→  --text-secondary: #A1A1AA;
 75→  --text-tertiary:  #71717A;
 76→  --text-disabled:  #52525B;
 77→
 78→  --accent:         #10B981;
 79→  --accent-hover:   #059669;
 80→  --accent-subtle:  rgba(16, 185, 129, 0.1);
 81→  --accent-text:    #34D399;
 82→
 83→  --success:        #22C55E;
 84→  --success-subtle: rgba(34, 197, 94, 0.1);
 85→  --warning:        #F59E0B;
 86→  --warning-subtle: rgba(245, 158, 11, 0.1);
 87→  --error:          #EF4444;
 88→  --error-subtle:   rgba(239, 68, 68, 0.1);
 89→
 90→  --glass-bg:            rgba(9, 9, 11, 0.8);
 91→  --glass-bg-strong:     rgba(9, 9, 11, 0.9);
 92→  --glass-border:        rgba(255, 255, 255, 0.06);
 93→  --glass-border-hover:  rgba(255, 255, 255, 0.1);
 94→  --glass-surface:       rgba(255, 255, 255, 0.04);
 95→  --glass-surface-hover: rgba(255, 255, 255, 0.06);
