306→.btn-gradient:hover { filter: brightness(1.15); transform: translateY(-1px); }
307→
308→.gradient-text {
309→  background: linear-gradient(135deg, var(--accent), var(--accent-text));
310→  -webkit-background-clip: text;
311→  -webkit-text-fill-color: transparent;
