313→
314→.ninja-card {
315→  background: var(--glass-surface);
316→  border: 1px solid var(--glass-border);
317→  border-radius: 0.75rem;
318→  backdrop-filter: blur(4px);
319→  transition: border-color 0.2s, box-shadow 0.2s, background 0.2s;
320→}
321→.ninja-card:hover {
322→  border-color: var(--glass-border-hover);
323→  background: var(--glass-surface-hover);
324→}
325→
326→.dot-grid-bg {
327→  background-image: radial-gradient(var(--border-default) 1px, transparent 1px);
328→  background-size: 20px 20px;
329→}
330→
331→.card-surface {
332→  background: var(--glass-surface);
333→  border: 1px solid var(--glass-border);
