335→  backdrop-filter: blur(4px);
336→}
337→
338→.line-clamp-2 {
339→  display: -webkit-box;
340→  -webkit-line-clamp: 2;
341→  -webkit-box-orient: vertical;
342→  overflow: hidden;
343→}
344→
345→/* Scroll progress bar */
346→#scroll-progress {
347→  position: fixed; top: 0; left: 0; height: 2px;
348→  background: linear-gradient(90deg, var(--accent), #818CF8, #C084FC);
349→  z-index: 9999;
350→  transition: width 0.1s linear;
351→  pointer-events: none;
