  1→import { useEffect, useMemo, useState, type PropsWithChildren } from 'react';
  2→import { Link, useLocation } from 'react-router-dom';
  3→import { demoAssignments } from '../../lib/demo-data';
  4→import { getSectorUiMeta } from '../../lib/constants';
  5→import { isSupabaseConfigured, supabase } from '../../lib/supabase';
  6→import { useAuth } from '../../hooks/useAuth';
  7→import { getProfileSectorTargets } from '../../utils/sector-targeting';
  8→
  9→interface NavItem {
 10→  label: string;
 11→  path: string;
 12→  icon: string;
 13→}
 14→
 15→const NAV_ITEMS: NavItem[] = [
 16→  { label: 'Radar', path: '/radar', icon: 'R' },
 17→  { label: 'Relances', path: '/pipeline', icon: 'S' },
 18→  { label: 'Ciblage', path: '/sources', icon: 'C' },
 19→  { label: 'Config', path: '/reglages', icon: 'P' },
 20→];
 21→
 22→/**
 23→ * Shell global de l'application avec sidebar desktop et tabbar mobile.
 24→ */
 25→export const AppLayout = ({ children }: PropsWithChildren): JSX.Element => {
 26→  const { profile, logout } = useAuth();
 27→  const location = useLocation();
 28→  const [unreadCount, setUnreadCount] = useState<number>(0);
 29→  const primaryTarget = getProfileSectorTargets(profile)[0];
 30→  const sectorMeta = getSectorUiMeta(primaryTarget?.id, primaryTarget?.label);
 31→
 32→  useEffect(() => {
 33→    if (!profile?.id) {
 34→      return;
 35→    }
 36→    if (!isSupabaseConfigured) {
 37→      const count = demoAssignments.filter((item) => item.status === 'new').length;
 38→      setUnreadCount(count);
 39→      return;
 40→    }
 41→    const fetchCount = async (): Promise<void> => {
 42→      const { count } = await supabase
 43→        .from('prospect_assignments')
 44→        .select('id', { head: true, count: 'exact' })
 45→        .eq('user_id', profile.id)
 46→        .eq('status', 'new');
 47→      setUnreadCount(count ?? 0);
 48→    };
 49→    void fetchCount();
 50→  }, [profile?.id]);
 51→
 52→  const creditsSummary = useMemo(() => {
 53→    if (!profile) {
 54→      return {
 55→        balance: 0,
 56→        spent: 0,
 57→        purchased: 0,
 58→        usagePercent: 0,
 59→      };
 60→    }
 61→    const spent = profile.credits_total_spent;
 62→    const purchased = profile.credits_total_purchased;
 63→    const usagePercent = purchased > 0 ? Math.min(100, (spent / purchased) * 100) : 0;
 64→    return {
 65→      balance: profile.credits_balance,
 66→      spent,
 67→      purchased,
 68→      usagePercent,
 69→    };
 70→  }, [profile]);
 71→
 72→  return (
 73→    <div className="min-h-screen bg-leadradar-bg text-white">
 74→      <aside className="fixed left-0 top-0 hidden h-screen w-[220px] border-r border-leadradar-border bg-leadradar-bg md:flex md:flex-col">
 75→        <div className="border-b border-leadradar-border px-5 py-6">
 76→          <div className="flex items-center gap-2">
 77→            <span className="grid h-7 w-7 place-items-center rounded-full bg-emerald-500/20 text-xs text-emerald-300">LR</span>
 78→            <h1 className="font-outfit text-xl font-bold">LeadRadar</h1>
 79→          </div>
 80→          <span
 81→            className="mt-3 inline-flex rounded-full px-2 py-1 text-xs font-semibold"
 82→            style={{ backgroundColor: `${sectorMeta.color}24`, color: sectorMeta.color }}
 83→          >
 84→            {sectorMeta.icon} {sectorMeta.label}
 85→          </span>
 86→        </div>
 87→
 88→        <nav className="flex-1 px-3 py-4">
 89→          <ul className="space-y-1.5">
 90→            {NAV_ITEMS.map((item) => {
 91→              const active = location.pathname === item.path;
 92→              return (
 93→                <li key={item.path}>
 94→                  <Link
 95→                    to={item.path}
 96→                    className="group relative flex items-center justify-between rounded-lg px-3 py-2 text-sm text-slate-300 transition hover:bg-slate-900/80 hover:text-white"
 97→                  >
 98→                    {active ? (
 99→                      <span
100→                        className="absolute left-0 top-1 h-[calc(100%-8px)] w-[3px] rounded-r"
101→                        style={{ backgroundColor: sectorMeta.color }}
102→                      />
103→                    ) : null}
104→                    <span className="ml-1 inline-flex items-center gap-2">
105→                      <span>{item.icon}</span>
106→                      <span>{item.label}</span>
107→                    </span>
108→                    {item.label === 'Radar' && unreadCount > 0 ? (
109→                      <span className="rounded-full bg-leadradar-border px-2 py-0.5 text-xs">{unreadCount}</span>
110→                    ) : null}
111→                  </Link>
112→                </li>
113→              );
114→            })}
115→          </ul>
116→        </nav>
117→
118→        <div className="border-t border-leadradar-border px-4 py-4">
119→          <div className="mb-3 rounded-lg border border-leadradar-border bg-leadradar-card px-3 py-2 text-xs text-slate-300">
120→            <div className="mb-1 flex items-center justify-between">
121→              <span>Credits disponibles</span>
122→              <span>{creditsSummary.balance}</span>
123→            </div>
124→            <p className="mb-1 text-[11px] text-slate-400">
125→              Consommes: {creditsSummary.spent} / Achetes: {creditsSummary.purchased}
126→            </p>
127→            <div className="h-1.5 w-full rounded-full bg-slate-800">
128→              <div
129→                className="h-full rounded-full"
130→                style={{
131→                  width: `${creditsSummary.usagePercent}%`,
132→                  backgroundColor: sectorMeta.color,
133→                }}
134→              />
135→            </div>
136→            <Link
137→              to="/reglages"
138→              className="mt-2 inline-flex w-full justify-center rounded-md border border-leadradar-border px-2 py-1 text-[11px] text-slate-200 transition hover:border-emerald-500 hover:text-emerald-300"
139→            >
140→              Recharger / Configurer
141→            </Link>
142→          </div>
143→          <div className="flex items-center justify-between">
144→            <div>
145→              <p className="text-sm font-semibold">{profile?.full_name ?? 'Utilisateur'}</p>
146→              <p className="text-xs text-slate-400">{profile?.email}</p>
147→            </div>
148→            <button
149→              type="button"
150→              onClick={() => {
151→                void logout();
152→              }}
153→              className="rounded-md border border-leadradar-border px-2 py-1 text-xs text-slate-300 transition hover:border-red-500 hover:text-red-300"
154→            >
155→              Quitter
156→            </button>
157→          </div>
158→        </div>
159→      </aside>
160→
161→      <main className="pb-20 md:ml-[220px] md:px-9 md:py-7">{children}</main>
162→
163→      <nav className="fixed bottom-0 left-0 right-0 z-40 border-t border-leadradar-border bg-leadradar-bg md:hidden">
164→        <ul className="grid grid-cols-4">
165→          {NAV_ITEMS.map((item) => {
166→            const active = location.pathname === item.path;
167→            return (
168→              <li key={item.path}>
169→                <Link
170→                  to={item.path}
171→                  className="relative flex flex-col items-center justify-center gap-1 py-2 text-[11px]"
172→                  style={{ color: active ? sectorMeta.color : '#94A3B8' }}
173→                >
174→                  <span className="text-sm">{item.icon}</span>
175→                  <span>{item.label}</span>
176→                </Link>
177→              </li>
178→            );
179→          })}
180→        </ul>
181→      </nav>
182→    </div>
183→  );
184→};
