11→      className="relative w-8 h-8 rounded-lg flex items-center justify-center text-[var(--text-secondary)] hover:text-[var(--text-primary)] hover:bg-[var(--glass-active)] transition-all duration-200"
12→      title={theme === 'dark' ? 'Passer en mode clair' : 'Passer en mode sombre'}
