 1→import React, { createContext, useContext, useEffect, useState } from 'react';
 2→
 3→type Theme = 'light' | 'dark';
 4→
 5→interface ThemeContextValue {
 6→  theme: Theme;
 7→  toggleTheme: () => void;
 8→  setTheme: (theme: Theme) => void;
 9→}
10→
11→const ThemeContext = createContext<ThemeContextValue>({
12→  theme: 'light',
13→  toggleTheme: () => {},
14→  setTheme: () => {},
15→});
16→
17→const STORAGE_KEY = 'citedby-theme';
18→
19→function getInitialTheme(): Theme {
20→  if (typeof window === 'undefined') return 'light';
21→  const stored = localStorage.getItem(STORAGE_KEY);
22→  if (stored === 'light' || stored === 'dark') return stored;
23→  return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
24→}
25→
26→export function ThemeProvider({ children }: { children: React.ReactNode }) {
27→  const [theme, setThemeState] = useState<Theme>(getInitialTheme);
28→
29→  useEffect(() => {
30→    const root = document.documentElement;
31→    if (theme === 'dark') {
32→      root.classList.add('dark');
33→    } else {
34→      root.classList.remove('dark');
35→    }
36→    document.body.style.backgroundColor = '';
37→    document.body.className = '';
38→    localStorage.setItem(STORAGE_KEY, theme);
39→  }, [theme]);
40→
41→  const toggleTheme = () => setThemeState(prev => (prev === 'light' ? 'dark' : 'light'));
42→  const setTheme = (t: Theme) => setThemeState(t);
43→
44→  return (
45→    <ThemeContext.Provider value={{ theme, toggleTheme, setTheme }}>
46→      {children}
47→    </ThemeContext.Provider>
48→  );
49→}
50→
51→export function useTheme() {
52→  return useContext(ThemeContext);
53→}
