import { useEffect, useMemo, useState, type PropsWithChildren } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { demoAssignments } from '../../lib/demo-data';
import { getSectorUiMeta } from '../../lib/constants';
import { isSupabaseConfigured, supabase } from '../../lib/supabase';
import { useAuth } from '../../hooks/useAuth';
import { getProfileSectorTargets } from '../../utils/sector-targeting';

interface NavItem {
  label: string;
  path: string;
  icon: string;
}

const NAV_ITEMS: NavItem[] = [
  { label: 'Radar', path: '/radar', icon: 'R' },
  { label: 'Relances', path: '/pipeline', icon: 'S' },
  { label: 'Ciblage', path: '/sources', icon: 'C' },
  { label: 'Config', path: '/reglages', icon: 'P' },
];

/**
 * Shell global de l'application avec sidebar desktop et tabbar mobile.
 */
export const AppLayout = ({ children }: PropsWithChildren): JSX.Element => {
  const { profile, logout } = useAuth();
  const location = useLocation();
  const [unreadCount, setUnreadCount] = useState<number>(0);
  const primaryTarget = getProfileSectorTargets(profile)[0];
  const sectorMeta = getSectorUiMeta(primaryTarget?.id, primaryTarget?.label);

  useEffect(() => {
    if (!profile?.id) {
      return;
    }
    if (!isSupabaseConfigured) {
      const count = demoAssignments.filter((item) => item.status === 'new').length;
      setUnreadCount(count);
      return;
    }
    const fetchCount = async (): Promise<void> => {
      const { count } = await supabase
        .from('prospect_assignments')
        .select('id', { head: true, count: 'exact' })
        .eq('user_id', profile.id)
        .eq('status', 'new');
      setUnreadCount(count ?? 0);
    };
    void fetchCount();
  }, [profile?.id]);

  const creditsSummary = useMemo(() => {
    if (!profile) {
      return {
        balance: 0,
        spent: 0,
        purchased: 0,
        usagePercent: 0,
      };
    }
    const spent = profile.credits_total_spent;
    const purchased = profile.credits_total_purchased;
    const usagePercent = purchased > 0 ? Math.min(100, (spent / purchased) * 100) : 0;
    return {
      balance: profile.credits_balance,
      spent,
      purchased,
      usagePercent,
    };
  }, [profile]);

  return (
    <div className="min-h-screen bg-leadradar-bg text-white">
      <aside className="fixed left-0 top-0 hidden h-screen w-[220px] border-r border-leadradar-border bg-leadradar-bg md:flex md:flex-col">
        <div className="border-b border-leadradar-border px-5 py-6">
          <div className="flex items-center gap-2">
            <span className="grid h-7 w-7 place-items-center rounded-full bg-emerald-500/20 text-xs text-emerald-300">LR</span>
            <h1 className="font-outfit text-xl font-bold">LeadRadar</h1>
          </div>
          <span
            className="mt-3 inline-flex rounded-full px-2 py-1 text-xs font-semibold"
            style={{ backgroundColor: `${sectorMeta.color}24`, color: sectorMeta.color }}
          >
            {sectorMeta.icon} {sectorMeta.label}
          </span>
        </div>

        <nav className="flex-1 px-3 py-4">
          <ul className="space-y-1.5">
            {NAV_ITEMS.map((item) => {
              const active = location.pathname === item.path;
              return (
                <li key={item.path}>
                  <Link
                    to={item.path}
                    className="group relative flex items-center justify-between rounded-lg px-3 py-2 text-sm text-slate-300 transition hover:bg-slate-900/80 hover:text-white"
                  >
                    {active ? (
                      <span
                        className="absolute left-0 top-1 h-[calc(100%-8px)] w-[3px] rounded-r"
                        style={{ backgroundColor: sectorMeta.color }}
                      />
                    ) : null}
                    <span className="ml-1 inline-flex items-center gap-2">
                      <span>{item.icon}</span>
                      <span>{item.label}</span>
                    </span>
                    {item.label === 'Radar' && unreadCount > 0 ? (
                      <span className="rounded-full bg-leadradar-border px-2 py-0.5 text-xs">{unreadCount}</span>
                    ) : null}
                  </Link>
                </li>
              );
            })}
          </ul>
        </nav>

        <div className="border-t border-leadradar-border px-4 py-4">
          <div className="mb-3 rounded-lg border border-leadradar-border bg-leadradar-card px-3 py-2 text-xs text-slate-300">
            <div className="mb-1 flex items-center justify-between">
              <span>Credits disponibles</span>
              <span>{creditsSummary.balance}</span>
            </div>
            <p className="mb-1 text-[11px] text-slate-400">
              Consommes: {creditsSummary.spent} / Achetes: {creditsSummary.purchased}
            </p>
            <div className="h-1.5 w-full rounded-full bg-slate-800">
              <div
                className="h-full rounded-full"
                style={{
                  width: `${creditsSummary.usagePercent}%`,
                  backgroundColor: sectorMeta.color,
                }}
              />
            </div>
            <Link
              to="/reglages"
              className="mt-2 inline-flex w-full justify-center rounded-md border border-leadradar-border px-2 py-1 text-[11px] text-slate-200 transition hover:border-emerald-500 hover:text-emerald-300"
            >
              Recharger / Configurer
            </Link>
          </div>
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-semibold">{profile?.full_name ?? 'Utilisateur'}</p>
              <p className="text-xs text-slate-400">{profile?.email}</p>
            </div>
            <button
              type="button"
              onClick={() => {
                void logout();
              }}
              className="rounded-md border border-leadradar-border px-2 py-1 text-xs text-slate-300 transition hover:border-red-500 hover:text-red-300"
            >
              Quitter
            </button>
          </div>
        </div>
      </aside>

      <main className="pb-20 md:ml-[220px] md:px-9 md:py-7">{children}</main>

      <nav className="fixed bottom-0 left-0 right-0 z-40 border-t border-leadradar-border bg-leadradar-bg md:hidden">
        <ul className="grid grid-cols-4">
          {NAV_ITEMS.map((item) => {
            const active = location.pathname === item.path;
            return (
              <li key={item.path}>
                <Link
                  to={item.path}
                  className="relative flex flex-col items-center justify-center gap-1 py-2 text-[11px]"
                  style={{ color: active ? sectorMeta.color : '#94A3B8' }}
                >
                  <span className="text-sm">{item.icon}</span>
                  <span>{item.label}</span>
                </Link>
              </li>
            );
          })}
        </ul>
      </nav>
    </div>
  );
};
