import React from 'react';

interface SkeletonProps {
  variant?: 'text' | 'card' | 'circle' | 'title' | 'avatar';
  className?: string;
  width?: string;
  height?: string;
  shimmer?: boolean;
}

const VARIANT_DEFAULTS = {
  text: 'h-4 w-48 rounded',
  title: 'h-6 w-64 rounded',
  card: 'h-32 w-full rounded-xl',
  circle: 'w-10 h-10 rounded-full',
  avatar: 'w-8 h-8 rounded-full',
};

export default function Skeleton({
  variant = 'text',
  className = '',
  width,
  height,
  shimmer = true,
}: SkeletonProps) {
  return (
    <div
      className={`${shimmer ? 'skeleton-shimmer' : 'bg-white/[0.06] animate-pulse'} ${VARIANT_DEFAULTS[variant]} ${className}`}
      style={{ ...(width && { width }), ...(height && { height }) }}
      role="status"
      aria-label="Loading..."
    />
  );
}

/** Group of skeleton lines — useful for loading text blocks */
export function SkeletonGroup({
  count = 3,
  variant = 'text',
  gap = 3,
}: {
  count?: number;
  variant?: 'text' | 'card' | 'circle' | 'title' | 'avatar';
  gap?: number;
}) {
  return (
    <div className={`space-y-${gap}`} role="status" aria-label="Loading content...">
      {Array.from({ length: count }).map((_, i) => (
        <Skeleton
          key={i}
          variant={variant}
          className={i === count - 1 && variant === 'text' ? 'w-32' : ''}
        />
      ))}
    </div>
  );
}

/** Card skeleton — mimics a KPI or content card */
export function SkeletonCard() {
  return (
    <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5 space-y-3">
      <Skeleton variant="text" className="w-24" />
      <Skeleton variant="title" className="w-16" />
      <Skeleton variant="text" className="w-32" />
    </div>
  );
}
